import{f as d,D as i,o as a,c as s,a2 as r,b as l,w as e,a as n,G as c,a5 as h}from"./chunks/framework.DHYrF-q6.js";const b=JSON.parse('{"title":"前端基础概览","description":"","frontmatter":{},"headers":[],"relativePath":"frontend/fundamentals/index.md","filePath":"frontend/fundamentals/index.md","lastUpdated":1780903847000}'),p={name:"frontend/fundamentals/index.md"};function E(g,t,A,u,S,m){const o=i("Mermaid");return a(),s("div",null,[t[1]||(t[1]=r('<h1 id="前端基础概览" tabindex="-1">前端基础概览 <a class="header-anchor" href="#前端基础概览" aria-label="Permalink to &quot;前端基础概览&quot;">​</a></h1><h2 id="⭐-面试重点速览" tabindex="-1">⭐ 面试重点速览 <a class="header-anchor" href="#⭐-面试重点速览" aria-label="Permalink to &quot;⭐ 面试重点速览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>知识模块</th><th>重点内容</th><th>面试频率</th></tr></thead><tbody><tr><td>HTML/CSS</td><td>语义化标签、盒模型、Flexbox/Grid、BFC、响应式设计</td><td>高</td></tr><tr><td>JavaScript 核心</td><td>原型链、闭包、this 指向、作用域链、深浅拷贝</td><td>极高</td></tr><tr><td>ES6+ 新特性</td><td>let/const、箭头函数、Promise、async-await、模块化</td><td>极高</td></tr><tr><td>TypeScript</td><td>类型系统、泛型、工具类型、interface vs type</td><td>中高</td></tr><tr><td>CSS 预处理器</td><td>Sass/SCSS 变量/嵌套/Mixin/函数、Less 对比、与原生 CSS 对比</td><td>中高</td></tr><tr><td>DOM &amp; BOM</td><td>DOM 操作、事件流(捕获/冒泡)、事件委托、BOM 核心 API</td><td>高</td></tr><tr><td>Web 存储</td><td>Cookie/localStorage/sessionStorage/IndexedDB 对比、Token 存储方案</td><td>中高</td></tr><tr><td>设计模式</td><td>观察者/发布订阅/单例/代理/装饰器/策略、MVC/MVVM</td><td>中高</td></tr><tr><td>API 设计</td><td>RESTful 设计规范、GraphQL 核心概念、两者对比选型</td><td>中</td></tr><tr><td>可访问性</td><td>ARIA 属性、键盘导航、语义化 HTML、WCAG 标准</td><td>中</td></tr><tr><td>Web Components</td><td>Custom Elements、Shadow DOM、HTML Templates</td><td>中</td></tr></tbody></table><hr><h2 id="模块概述" tabindex="-1">模块概述 <a class="header-anchor" href="#模块概述" aria-label="Permalink to &quot;模块概述&quot;">​</a></h2><p>前端基础知识是高级前端工程师面试的基石。无论框架如何演进（React、Vue、Angular、Svelte），底层始终是 HTML、CSS 和 JavaScript 三位一体。本模块面向<strong>高级前端面试准备</strong>，深入剖析每个知识点的底层原理、常见陷阱和面试追问方向。</p><div class="danger custom-block"><p class="custom-block-title">为什么前端基础如此重要？</p><ul><li>大厂面试中，基础题占比通常在 40%~60%，是筛选候选人的第一道门槛</li><li>框架层的问题（如 Vue 响应式、React Fiber）本质上是基础知识的延伸应用</li><li>基础不牢的候选人，即使框架经验丰富，也容易被一道&quot;手写深拷贝&quot;或&quot;BFC 原理&quot;淘汰</li></ul></div><hr><h2 id="知识图谱" tabindex="-1">知识图谱 <a class="header-anchor" href="#知识图谱" aria-label="Permalink to &quot;知识图谱&quot;">​</a></h2>',9)),(a(),l(h,null,{default:e(()=>[c(o,{id:"mermaid-174",class:"mermaid",graph:"mindmap%0A%20%20root((%E5%89%8D%E7%AB%AF%E5%9F%BA%E7%A1%80))%0A%20%20%20%20HTML%2FCSS%0A%20%20%20%20%20%20%E8%AF%AD%E4%B9%89%E5%8C%96%E6%A0%87%E7%AD%BE%0A%20%20%20%20%20%20%E7%9B%92%E6%A8%A1%E5%9E%8B%0A%20%20%20%20%20%20Flexbox%20%2F%20Grid%0A%20%20%20%20%20%20BFC%0A%20%20%20%20%20%20%E5%93%8D%E5%BA%94%E5%BC%8F%E8%AE%BE%E8%AE%A1%0A%20%20%20%20%20%20Canvas%20%2F%20SVG%0A%20%20%20%20%20%20%E8%A1%A8%E5%8D%95%E9%AA%8C%E8%AF%81%0A%20%20%20%20JavaScript%20%E6%A0%B8%E5%BF%83%0A%20%20%20%20%20%20%E5%8E%9F%E5%9E%8B%E9%93%BE%0A%20%20%20%20%20%20%E9%97%AD%E5%8C%85%0A%20%20%20%20%20%20this%20%E6%8C%87%E5%90%91%0A%20%20%20%20%20%20%E4%BD%9C%E7%94%A8%E5%9F%9F%E9%93%BE%0A%20%20%20%20%20%20%E6%B7%B1%E6%B5%85%E6%8B%B7%E8%B4%9D%0A%20%20%20%20%20%20Event%20Loop%0A%20%20%20%20ES6%2B%20%E6%96%B0%E7%89%B9%E6%80%A7%0A%20%20%20%20%20%20let%20%2F%20const%0A%20%20%20%20%20%20%E7%AE%AD%E5%A4%B4%E5%87%BD%E6%95%B0%0A%20%20%20%20%20%20%E8%A7%A3%E6%9E%84%E8%B5%8B%E5%80%BC%0A%20%20%20%20%20%20%E6%A8%A1%E5%9D%97%E5%8C%96%0A%20%20%20%20%20%20Promise%0A%20%20%20%20%20%20async-await%0A%20%20%20%20%20%20Optional%20Chaining%0A%20%20%20%20TypeScript%0A%20%20%20%20%20%20%E5%9F%BA%E7%A1%80%E7%B1%BB%E5%9E%8B%0A%20%20%20%20%20%20%E6%B3%9B%E5%9E%8B%0A%20%20%20%20%20%20%E5%B7%A5%E5%85%B7%E7%B1%BB%E5%9E%8B%0A%20%20%20%20%20%20%E7%B1%BB%E5%9E%8B%E5%AE%88%E5%8D%AB%0A%20%20%20%20%20%20%E6%9E%9A%E4%B8%BE%0A%20%20%20%20%20%20%E6%9D%A1%E4%BB%B6%E7%B1%BB%E5%9E%8B%0A"})]),fallback:e(()=>[...t[0]||(t[0]=[n(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=r('<hr><h2 id="四个子模块简介" tabindex="-1">四个子模块简介 <a class="header-anchor" href="#四个子模块简介" aria-label="Permalink to &quot;四个子模块简介&quot;">​</a></h2><table tabindex="0"><thead><tr><th>子模块</th><th>定位</th><th>核心难点</th><th>课时建议</th></tr></thead><tbody><tr><td><a href="./html-css">HTML/CSS 核心</a></td><td>页面结构与样式基础</td><td>BFC 原理、Flex/Grid 布局选择、响应式策略</td><td>2~3 天</td></tr><tr><td><a href="./javascript-core">JavaScript 核心概念</a></td><td>语言底层机制</td><td>原型链查找、闭包内存模型、this 绑定优先级</td><td>3~5 天</td></tr><tr><td><a href="./es6-plus">ES6+ 新特性</a></td><td>现代 JS 开发规范</td><td>Promise 实现原理、async-await 本质、Tree Shaking</td><td>3~4 天</td></tr><tr><td><a href="./typescript">TypeScript 核心</a></td><td>类型系统保障</td><td>工具类型实现、条件类型推导、interface vs type</td><td>2~3 天</td></tr><tr><td><a href="./css-preprocessors">CSS 预处理器</a></td><td>CSS 工程化基础</td><td>Sass/Less 核心特性、@mixin vs @extend、@use vs @import</td><td>1~2 天</td></tr><tr><td><a href="./dom-bom">DOM &amp; BOM 核心</a></td><td>浏览器 API 基础</td><td>DOM 操作/事件流/事件委托、BOM 核心 API 总结</td><td>1~2 天</td></tr><tr><td><a href="./web-storage">Web 存储方案</a></td><td>客户端存储</td><td>Cookie/localStorage/sessionStorage/IndexedDB 对比</td><td>1 天</td></tr><tr><td><a href="./design-patterns">前端设计模式</a></td><td>架构思维</td><td>八大设计模式、MVC/MVP/MVVM 对比</td><td>2~3 天</td></tr><tr><td><a href="./api-design">API 设计</a></td><td>接口设计</td><td>RESTful 规范、GraphQL 核心概念、选型对比</td><td>1 天</td></tr><tr><td><a href="./accessibility">可访问性</a></td><td>A11y 基础</td><td>ARIA 属性、键盘导航、语义化 HTML</td><td>1 天</td></tr><tr><td><a href="./web-components">Web Components</a></td><td>原生组件方案</td><td>Custom Elements、Shadow DOM、与 Vue/React 对比</td><td>1 天</td></tr></tbody></table><hr><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to &quot;学习路径建议&quot;">​</a></h2><h3 id="阶段一-html-css-1-2-天" tabindex="-1">阶段一：HTML/CSS（1~2 天） <a class="header-anchor" href="#阶段一-html-css-1-2-天" aria-label="Permalink to &quot;阶段一：HTML/CSS（1~2 天）&quot;">​</a></h3><p>从最直观的页面呈现入手，重点掌握：</p><ol><li><strong>盒模型</strong>是 CSS 布局的基石，理解 <code>content-box</code> vs <code>border-box</code> 的差异</li><li><strong>BFC</strong> 是面试高频考点，需要理解触发条件和应用场景（清除浮动、防止 margin 折叠）</li><li><strong>Flexbox</strong> 和 <strong>Grid</strong> 分别适用于一维和二维布局，能独立完成常见布局需求</li><li>响应式设计中 <strong>rem/vw/vh</strong> 的原理和选择策略</li></ol><div class="tip custom-block"><p class="custom-block-title">面试建议</p><p>CSS 面试通常以&quot;实现某个布局效果&quot;为目的，而非单纯背诵属性。多动手写实际布局代码比死记硬背更有效。</p></div><h3 id="阶段二-javascript-核心-3-5-天" tabindex="-1">阶段二：JavaScript 核心（3~5 天） <a class="header-anchor" href="#阶段二-javascript-核心-3-5-天" aria-label="Permalink to &quot;阶段二：JavaScript 核心（3~5 天）&quot;">​</a></h3><p>这是整个前端基础中最关键的部分，投入时间应该最多：</p><ol><li><strong>原型链</strong>：画图理解 <code>__proto__</code> 和 <code>prototype</code> 的指向关系，理解 <code>instanceof</code> 原理</li><li><strong>闭包</strong>：理解词法作用域 + 函数作为值传递 = 闭包，结合 Event Loop 理解闭包中变量的存活时机</li><li><strong>this 指向</strong>：熟记四条绑定规则及优先级，箭头函数的特殊行为</li><li><strong>深浅拷贝</strong>：能手写深拷贝，处理循环引用、特殊对象（Date/RegExp/Map/Set）</li><li><strong>Event Loop</strong>：理解宏任务/微任务的执行顺序，结合 Promise 和 async-await</li></ol><div class="danger custom-block"><p class="custom-block-title">避坑指南</p><ul><li>不要只背诵概念，一定要能手写代码</li><li>原型链题目建议画图辅助理解</li><li>闭包相关的内存泄漏问题要能说清楚原因和解决方案</li></ul></div><h3 id="阶段三-es6-新特性-3-4-天" tabindex="-1">阶段三：ES6+ 新特性（3~4 天） <a class="header-anchor" href="#阶段三-es6-新特性-3-4-天" aria-label="Permalink to &quot;阶段三：ES6+ 新特性（3~4 天）&quot;">​</a></h3><p>现代前端开发的&quot;新标准&quot;，重点在于：</p><ol><li><strong>let/const/var 对比</strong>：块级作用域、TDZ、变量提升</li><li><strong>箭头函数 vs 普通函数</strong>：this/arguments/prototype/new 四个维度的差异</li><li><strong>Promise</strong>：状态机模型、链式调用、手写 Promise.all/race/allSettled/any</li><li><strong>async-await</strong>：Generator + 自动执行器的本质</li><li><strong>模块化</strong>：ESM vs CommonJS，Tree Shaking 原理</li></ol><h3 id="阶段四-typescript-2-3-天" tabindex="-1">阶段四：TypeScript（2~3 天） <a class="header-anchor" href="#阶段四-typescript-2-3-天" aria-label="Permalink to &quot;阶段四：TypeScript（2~3 天）&quot;">​</a></h3><p>大厂必备技能，核心在于类型体操：</p><ol><li><strong>基础类型系统</strong>：interface vs type、联合类型、交叉类型</li><li><strong>泛型</strong>：泛型约束、条件类型、infer 关键字</li><li><strong>工具类型</strong>：Partial/Required/Readonly/Pick/Omit/Record/Exclude/Extract/ReturnType</li><li><strong>类型守卫</strong>：typeof/instanceof/in/自定义类型谓词（is）</li></ol><hr><h2 id="面试追问环节" tabindex="-1">面试追问环节 <a class="header-anchor" href="#面试追问环节" aria-label="Permalink to &quot;面试追问环节&quot;">​</a></h2><p><strong>Q：前端基础知识中，你认为最重要的是哪一块？为什么？</strong></p><p>JavaScript 核心概念（原型链、闭包、this、Event Loop）是最重要的。原因有三：</p><ol><li>它们是理解所有前端框架的基础（Vue 的响应式依赖闭包、React Hooks 依赖闭包）</li><li>它们是面试中区分初级和高级候选人的分水岭</li><li>框架会过时，但 JavaScript 基础是长期不变的</li></ol><p><strong>Q：如果面试官让你比较前端和后端的复杂度，你怎么回答？</strong></p><p>前端复杂在于<strong>状态管理和异步编排</strong>，后端复杂在于<strong>并发控制和数据一致性</strong>。前端的状态分散在 DOM、组件状态、路由、缓存等多个维度，异步操作的时序控制（Promise 链、竞态条件）是高频出错点。后端的并发问题有成熟方案（事务、锁、消息队列），而前端的复杂度往往被低估。</p><p><strong>Q：TypeScript 到底值不值得学？小项目用 TS 是不是过度设计？</strong></p><p>TS 的价值与项目规模成正比，但即使小项目，类型系统也能带来显著收益：</p><ul><li>编译期发现类型错误，减少运行时 bug</li><li>更好的 IDE 智能提示和重构支持</li><li>类型注解即文档，降低维护成本 对于任何超过 3 个文件的项目，TS 的收益就超过成本。唯一的&quot;成本&quot;是学习曲线，但这是一次性投入。</li></ul><hr><h2 id="面试策略建议" tabindex="-1">面试策略建议 <a class="header-anchor" href="#面试策略建议" aria-label="Permalink to &quot;面试策略建议&quot;">​</a></h2><h3 id="基础题回答框架" tabindex="-1">基础题回答框架 <a class="header-anchor" href="#基础题回答框架" aria-label="Permalink to &quot;基础题回答框架&quot;">​</a></h3><p>面试中遇到基础题，推荐使用 <strong>STAR-L 框架</strong>：</p><ol><li><strong>S（Scenario）</strong>：先给出概念定义，一句话说清楚&quot;是什么&quot;</li><li><strong>T（Theory）</strong>：解释底层原理，展示深度理解</li><li><strong>A（Application）</strong>：举出实际应用场景，证明你不仅懂理论</li><li><strong>R（Related）</strong>：关联相关知识，展示广度</li><li><strong>L（Limitation）</strong>：指出该技术的局限性/陷阱，展示批判性思维</li></ol><p><strong>示例：面试官问&quot;说一下闭包&quot;</strong></p><blockquote><p>&quot;闭包是指函数能够记住并访问其词法作用域，即使该函数在其词法作用域之外执行（S）。其原理是 JavaScript 引擎在函数创建时会保存对其外部词法环境的引用，形成作用域链（T）。实际应用中，闭包常用于模块模式、柯里化、防抖节流等场景（A）。需要注意的是，闭包会导致外部变量无法被 GC 回收，如果使用不当可能造成内存泄漏（L）。&quot;</p></blockquote><h3 id="常见陷阱提醒" tabindex="-1">常见陷阱提醒 <a class="header-anchor" href="#常见陷阱提醒" aria-label="Permalink to &quot;常见陷阱提醒&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">面试中容易翻车的点</p><ol><li><strong>概念混淆</strong>：把原型链的 <code>__proto__</code> 和 <code>prototype</code> 说反</li><li><strong>只背不写</strong>：说得出闭包定义，但写不出循环 + setTimeout 的解决方案</li><li><strong>深度不足</strong>：知道 BFC 能清除浮动，但说不清为什么</li><li><strong>范围过窄</strong>：知道 Promise.all 的用法，但不知 allSettled 和 any 的区别</li><li><strong>避重就轻</strong>：面试官问深拷贝，只回答 JSON 方案而不提循环引用和特殊对象处理</li></ol></div>',38))])}const f=d(p,[["render",E]]);export{b as __pageData,f as default};
